def cloud_optical_depth(frac, lwp_gm2, re_liq_um, iwp_gm2, re_ice_um, iceflag=2):
    """
    Compute cloud absorption optical depth per RRTM band (INFLAG=2).

    Mirrors Fortran CLDPROP subroutine logic exactly.
    LIQFLAG=1 (Hu & Stamnes 1993) is always used for liquid clouds.
    ICEFLAG=2 (Streamer) or ICEFLAG=3 (Fu et al.) is used for ice clouds.

    Parameters
    ----------
    frac : array_like, shape (nlayers,)
        Cloud fraction per layer [0, 1].  NaN is treated as clear-sky (0).
    lwp_gm2 : array_like, shape (nlayers,)
        Liquid water path [g/m^2].  NaN treated as 0.
    re_liq_um : array_like, shape (nlayers,)
        Liquid effective radius [microns].  Ignored when lwp_gm2 <= 0.
    iwp_gm2 : array_like, shape (nlayers,)
        Ice water path [g/m^2].  NaN treated as 0.
    re_ice_um : array_like, shape (nlayers,)
        Ice effective radius (ICEFLAG=2) or generalized effective size
        (ICEFLAG=3) [microns].  Ignored when iwp_gm2 <= 0.
    iceflag : int, optional
        2 = Streamer v3.0 spherical ice (default), 3 = Fu et al. hexagonal ice.

    Returns
    -------
    tau_cloud : np.ndarray, shape (nlayers, 16)
        Cloud absorption optical depth per layer and RRTM band.
    frac_clean : np.ndarray, shape (nlayers,)
        Cloud fraction with NaN replaced by 0.
    """
    nlayers = len(frac)
    tau_cloud = np.zeros((nlayers, 16))
    frac_clean = np.where(np.isfinite(frac), frac, 0.0)

    for lay in range(nlayers):
        f = frac_clean[lay]
        if f <= 0.0:
            continue

        lwp = lwp_gm2[lay]   if np.isfinite(lwp_gm2[lay])   else 0.0
        re_l = re_liq_um[lay] if np.isfinite(re_liq_um[lay]) else 0.0
        iwp = iwp_gm2[lay]   if np.isfinite(iwp_gm2[lay])   else 0.0
        re_i = re_ice_um[lay] if np.isfinite(re_ice_um[lay]) else 0.0

        for b in range(16):
            tliq = 0.0
            tice = 0.0

            # ---- Liquid cloud: LIQFLAG=1 (Hu & Stamnes 1993) ----
            # Fortran: INDEX = RADLIQ - 1.5 (implicit INT truncation)
            # Valid range: RADLIQ in [2.5, 60.0] microns
            if lwp > 0.0 and re_l >= 2.5:
                idx = int(re_l - 1.5)        # Fortran 1-based INDEX
                idx = max(1, min(57, idx))   # clamp: Fortran IF(INDEX==0)→1, IF(INDEX==58)→57
                fint = re_l - 1.5 - float(idx)
                # Fortran ABSLIQ1(idx, b) → Python ABSLIQ1[idx-1, b]
                absliq = ABSLIQ1[idx - 1, b] + fint * (ABSLIQ1[idx, b] - ABSLIQ1[idx - 1, b])
                tliq = lwp * absliq

            # ---- Ice cloud: ICEFLAG=2 or 3 ----
            if iwp > 0.0 and re_i >= 5.0:
                factor = (re_i - 2.0) / 3.0
                idx = int(factor)             # Fortran 1-based INDEX
                if iceflag == 2:
                    # Valid range: re in [5, 131] microns
                    # Fortran: IF (INDEX .EQ. 43) INDEX = 42
                    idx = min(idx, 42)
                    absice = ABSICE2[idx - 1, b] + (factor - float(idx)) * (ABSICE2[idx, b] - ABSICE2[idx - 1, b])
                else:  # iceflag == 3
                    # Valid range: dge in [5, 140] microns
                    # Fortran: IF (INDEX .EQ. 46) INDEX = 45
                    idx = min(idx, 45)
                    absice = ABSICE3[idx - 1, b] + (factor - float(idx)) * (ABSICE3[idx, b] - ABSICE3[idx - 1, b])
                tice = iwp * absice

            tau_cloud[lay, b] = tliq + tice

    return tau_cloud, frac_clean
